class Solution:
    def addMinimum(self, word: str) -> int:
        stack = []
        count = 0
        for char in word:
            if char == 'a':
                stack.append(char)
            elif char == 'b':
                if stack and stack[-1] == 'a':
                    stack.pop()
                    stack.append('ab')
                else:
                    count += 1
                    stack.append('ab')
            elif char == 'c':
                if stack and stack[-1] == 'ab':
                    stack.pop()
                else:
                    if stack and stack[-1] == 'a':
                        count += 1
                        stack.pop()
                    count += 1
        while stack:
            if stack[-1] == 'a':
                count += 2
            elif stack[-1] == 'ab':
                count += 1
            stack.pop()
        return count
